function mk(name, city, county, month, special) {
  return `${name} is one of ${county}'s most cherished market traditions — a beloved ${month} gathering in ${city} that brings vendors and visitors from across the region for a celebration of Swedish market culture, quality goods and genuine community spirit.\n\n${special}\n\nThe Swedish knallemarknad tradition — stretching back centuries through the travelling merchants who connected Swedish communities — is alive and well in ${city}, creating a commercial and social gathering that sustains local identity and community bonds across generations.\n\nFor vendors, ${name} provides excellent access to a quality Swedish regional audience with strong commercial engagement and the enthusiastic buyer participation that makes Swedish community markets among the finest trading environments in Scandinavia.`;
}

